+
+    let content: Vec<Vec<rich_rust::segment::Segment>> = content_lines
+        .iter()
+        .map(|line| {
+            let text = markup::render_or_plain(line);
+            text.render("")
+                .into_iter()
+                .map(rich_rust::segment::Segment::into_owned)
+                .collect()
+        })
+        .collect();
