+    let pad = center_padding(cell_len(footer), width);
+    console.print(&format!("{pad}[dim]{footer}[/]"));
+
+    let version = "v0.1 • MIT License";
+    let pad_ver = center_padding(cell_len(version), width);
+    console.print(&format!("{pad_ver}[dim]{version}[/]"));
